      managerNames.add("10470726"); //Latriece Prince-Wheeler
      managerNames.add("10270480"); //Timothy Bode
      
      if(identity != null && !identity.isInactive()){
        String email = identity.getAttribute("primaryEmail");
        if(Util.isNotNullOrEmpty(email)){
            Identity manager = identity.getManager();
            int i=1;

            while (null != manager){
              if(null!=manager && managerNames.contains(manager.getName())){
                return true;
              }
              i++;
              Identity ident=manager;
              manager = ident.getManager();  
              
              //failsafe in case of loop in chain
              if(i > 50)
                break;
            }
        }
      }
      
      return false;
